#include <stdio.h>
#include <inttypes.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long D, d, P, Q;
        scanf("%lld %lld %lld %lld", &D, &d, &P, &Q);
        long long n = D / d;
        long long r = D % d;
        long long total = d * n * P;
        total += d * Q * n * (n - 1) / 2;
        total += r * (P + n * Q);
        printf("%lld\n", total);
    }
    return 0;
}

